create extension if not exists "uuid-ossp";
create table users(id uuid primary key default auth.uid(), role text not null check(role in ('founder','investor','investor_member','admin')), full_name text, created_at timestamptz default now(), updated_at timestamptz default now());
create table organizations(id uuid primary key default uuid_generate_v4(), name text not null, created_by uuid references users(id), created_at timestamptz default now(), updated_at timestamptz default now());
create table organization_members(id uuid primary key default uuid_generate_v4(), organization_id uuid references organizations(id) on delete cascade, user_id uuid references users(id) on delete cascade, role text not null, created_at timestamptz default now(), updated_at timestamptz default now());
create table startups(id uuid primary key default uuid_generate_v4(), founder_id uuid references users(id), organization_id uuid references organizations(id), company_name text not null, sector text, stage text, country text, funding_target numeric, valuation numeric, traction text, revenue numeric, team_size int, created_at timestamptz default now(), updated_at timestamptz default now());
create table deal_rooms(id uuid primary key default uuid_generate_v4(), startup_id uuid references startups(id) on delete cascade, investor_org_id uuid references organizations(id), status text default 'new', created_at timestamptz default now(), updated_at timestamptz default now());
create table documents(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, uploader_id uuid references users(id), category text, status text, storage_path text, created_at timestamptz default now(), updated_at timestamptz default now());
create table document_requests(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, requested_by uuid references users(id), category text, notes text, status text default 'requested', created_at timestamptz default now(), updated_at timestamptz default now());
create table due_diligence_items(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, section text, status text, owner_id uuid references users(id), notes text, due_date date, created_at timestamptz default now(), updated_at timestamptz default now());
create table messages(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, sender_id uuid references users(id), body text, private_to_org boolean default false, created_at timestamptz default now(), updated_at timestamptz default now());
create table notes(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, author_id uuid references users(id), body text, created_at timestamptz default now(), updated_at timestamptz default now());
create table ai_reports(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, report_type text, content text, generated_by uuid references users(id), created_at timestamptz default now(), updated_at timestamptz default now());
create table decisions(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, decided_by uuid references users(id), status text, score int, risk_level text, next_action text, follow_up_date date, notes text, created_at timestamptz default now(), updated_at timestamptz default now());
create table activities(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, actor_id uuid references users(id), action text, metadata jsonb, created_at timestamptz default now());
create table meetings(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, title text, scheduled_at timestamptz, attendees jsonb, created_at timestamptz default now(), updated_at timestamptz default now());
create table tasks(id uuid primary key default uuid_generate_v4(), deal_room_id uuid references deal_rooms(id) on delete cascade, owner_id uuid references users(id), title text, status text, due_date date, created_at timestamptz default now(), updated_at timestamptz default now());
alter table startups enable row level security; alter table deal_rooms enable row level security; alter table documents enable row level security; alter table due_diligence_items enable row level security; alter table messages enable row level security;
create policy founder_startups on startups for all using (founder_id=auth.uid());
create policy founder_deal_rooms on deal_rooms for select using (startup_id in (select id from startups where founder_id=auth.uid()));
create policy investor_deal_rooms on deal_rooms for select using (investor_org_id in (select organization_id from organization_members where user_id=auth.uid()));
